const res = await fetch('http://localhost:3456/api/tasks', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Kspec-Dir': cwd
  },
  body: JSON.stringify({
    title: String(task.title ?? ''),
    description: task.description ? String(task.description) : undefined,
    priority: kspecPriority,
    type: kspecType,
    status: kspecStatus,
    tags: [`migrated-from:${String(task.id ?? '')}`]
  })
})

async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
  try {
    await api('POST', '/api/tasks', cwd, {
      title: params.title,
      description: params.description,
      priority: params.priority,
      type: params.type,
      tags: params.tags?.split(',').map(t => t.trim()).filter(Boolean),
      automation: params.automation || undefined
    })
    return { success: true }
  } catch (e) {
    return { success: false, error: String(e) }
  }
}

